import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { instanceToPlain, plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { rollbar } from '@config/rollbar.config';

import { DefaultUnitPriceModel } from '@modules/db/default-unit-prices/models/default-unit-price.model';
import { IDefaultUnitPriceCreate } from '@modules/db/default-unit-prices/types/default-unit-price.create.interface';
import { StyleColorModel } from '@modules/db/style-colors/models/style-color.model';
import { IStyleColorCreate } from '@modules/db/style-colors/types/style-color.create.interface';
import { BaseStyleDto } from '@modules/db/styles/dto/style.base.dto';
import { FindByStyleIdsDto } from '@modules/db/styles/dto/style.find.dto';
import { IStyleBase } from '@modules/db/styles/types/style.base.interface';
import { IStyleCreate } from '@modules/db/styles/types/style.create.interface';
import { StylesMvModel } from '@modules/db/styles-mv/models/styles-mv.model';

import {
	KNEX_READ_CONNECTION,
	KNEX_WRITE_CONNECTION,
	TABLE_NAME_STYLES,
} from '@constants/db.constant';
import { FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS } from '@constants/recommendations.constants';

@Injectable()
export class StyleModel {
	private readonly logger = new Logger(StyleModel.name);
	private readonly tableName = TABLE_NAME_STYLES;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
		private readonly styleColorModel: StyleColorModel,
		private readonly defaultUnitPriceModel: DefaultUnitPriceModel,
		private readonly stylesMvModel: StylesMvModel,
	) {}

	async findByStyleId({
		styleId,
	}: {
		styleId: IStyleBase['style_id'];
	}): Promise<IStyleBase | null> {
		try {
			const result = await this.knexRead<BaseStyleDto>(this.tableName)
				.where({ style_id: styleId })
				.whereNull('deleted_at')
				.first()
				.then((result) => {
					if (!result) {
						return null;
					}

					return {
						// eslint-disable-next-line
						...result,
						categories_ids:
							typeof result.categories_ids === 'string'
								? (JSON.parse(result.categories_ids) as number[])
								: result.categories_ids,
						categories_with_parents_ids:
							typeof result.categories_with_parents_ids === 'string'
								? (JSON.parse(result.categories_with_parents_ids) as number[])
								: result.categories_with_parents_ids,
					};
				});

			if (!result) {
				this.logger.warn(`No style found for styleId ${styleId}`);
